using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    [Header("Player Stats")]
    public int maxHealth = 100;
    public int currentHealth = 100;
    public int currency = 1000;
    public int baseDamage = 10;
    public float damageMultiplier = 1f;

    [Header("IAP / Shop")]
    public int healthPotionPrice = 50;
    public int swordUpgradePrice = 200;
    public int healthPotionHealAmount = 25;
    public int swordUpgradeDamageIncrease = 5;

    private void Start()
    {
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
    }

    public int CalculateDamage()
    {
        return Mathf.RoundToInt(baseDamage * damageMultiplier);
    }

    public void TakeDamage(int incomingDamage, int defense = 0)
    {
        int finalDamage = Mathf.Max(0, incomingDamage - defense);
        currentHealth -= finalDamage;
        if (currentHealth < 0)
        {
            currentHealth = 0;
        }
    }

    public void Heal(int amount)
    {
        currentHealth = Mathf.Min(currentHealth + amount, maxHealth);
    }

    public bool CanAfford(int price)
    {
        return currency >= price;
    }

    public bool SpendCurrency(int amount)
    {
        if (!CanAfford(amount))
        {
            return false;
        }

        currency -= amount;
        return true;
    }

    public void AddCurrency(int amount)
    {
        currency += Mathf.Max(0, amount);
    }

    public bool BuyHealthPotion()
    {
        if (!SpendCurrency(healthPotionPrice))
        {
            return false;
        }

        Heal(healthPotionHealAmount);
        return true;
    }

    public bool BuySwordUpgrade()
    {
        if (!SpendCurrency(swordUpgradePrice))
        {
            return false;
        }

        baseDamage += swordUpgradeDamageIncrease;
        swordUpgradePrice = CalculateNextPrice(swordUpgradePrice, 1.25f);
        return true;
    }

    public int CalculateNextPrice(int currentPrice, float multiplier)
    {
        return Mathf.CeilToInt(currentPrice * multiplier);
    }
}

public class Enemy : MonoBehaviour
{
    public int maxHealth = 50;
    public int currentHealth = 50;
    public int defense = 2;
    public int contactDamage = 10;

    private void Start()
    {
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
    }

    public void TakeDamage(int damage)
    {
        int finalDamage = Mathf.Max(0, damage - defense);
        currentHealth -= finalDamage;

        if (currentHealth <= 0)
        {
            currentHealth = 0;
            Die();
        }
    }

    private void Die()
    {
        Destroy(gameObject);
    }
}

public class PlayerCombat : MonoBehaviour
{
    public PlayerStats playerStats;

    public void AttackEnemy(Enemy enemy)
    {
        if (playerStats == null || enemy == null)
        {
            return;
        }

        int damage = playerStats.CalculateDamage();
        enemy.TakeDamage(damage);
    }
}

public class ShopManager : MonoBehaviour
{
    public PlayerStats playerStats;

    public bool PurchaseHealthPotion()
    {
        if (playerStats == null)
        {
            return false;
        }

        return playerStats.BuyHealthPotion();
    }

    public bool PurchaseSwordUpgrade()
    {
        if (playerStats == null)
        {
            return false;
        }

        return playerStats.BuySwordUpgrade();
    }

    public int GetHealthPotionPrice()
    {
        if (playerStats == null)
        {
            return 0;
        }

        return playerStats.healthPotionPrice;
    }

    public int GetSwordUpgradePrice()
    {
        if (playerStats == null)
        {
            return 0;
        }

        return playerStats.swordUpgradePrice;
    }
